svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
    var dataLayerEl = document.getElementById('data-layer');
    var legendRoot = document.getElementById('legend-root');
    var SERIES_REVEAL_DURATION = 0.8;
    var seriesGroups = [];
    var pointItems = [];

    var series = [
      {
        id: 1,
        name: '1994-99 Cycle',
        value: '5.50%',
        ci: 1,
        points: [
          { x: 68, y: 380, value: '3.0%', label: '1994 - Start' },
          { x: 179, y: 260, value: '6.0%', label: '1995 - Peak' },
          { x: 206, y: 280, value: '5.5%', label: '1996 - Cut' },
          { x: 287, y: 320, value: '4.75%', label: '1998 - Easing' },
          { x: 314, y: 280, value: '5.5%', label: '1999 - Rehike' }
        ]
      },
      {
        id: 2,
        name: '2000-03 Easing',
        value: '1.00%',
        ci: 2,
        points: [
          { x: 314, y: 240, value: '6.5%', label: '2000 - Peak' },
          { x: 368, y: 340, value: '4.0%', label: '2001 - Cutting' },
          { x: 395, y: 420, value: '2.0%', label: '2002 - Easing' },
          { x: 422, y: 460, value: '1.0%', label: '2003 - Low' }
        ]
      },
      {
        id: 3,
        name: '2004-06 Hiking',
        value: '5.25%',
        ci: 3,
        points: [
          { x: 449, y: 420, value: '2.0%', label: '2004 - Hiking' },
          { x: 476, y: 340, value: '4.0%', label: '2005 - Hiking' },
          { x: 503, y: 300, value: '5.0%', label: '2006 - Hiking' },
          { x: 530, y: 292, value: '5.25%', label: '2006 - Peak' }
        ]
      },
      {
        id: 4,
        name: '2007-09 GFC Cut',
        value: '0.25%',
        ci: 4,
        points: [
          { x: 557, y: 340, value: '4.0%', label: '2007 - Cutting' },
          { x: 584, y: 420, value: '2.0%', label: '2008 - GFC' },
          { x: 611, y: 480, value: '0.5%', label: '2008 - Crisis' },
          { x: 638, y: 490, value: '0.25%', label: '2009 - Floor' }
        ]
      },
      {
        id: 5,
        name: '2015-20 Cycle',
        value: '0.25%',
        ci: 5,
        points: [
          { x: 665, y: 460, value: '1.0%', label: '2016 - Liftoff' },
          { x: 692, y: 430, value: '1.75%', label: '2017 - Hiking' },
          { x: 719, y: 400, value: '2.5%', label: '2018 - Peak' },
          { x: 746, y: 490, value: '0.25%', label: '2020 - COVID' }
        ]
      },
      {
        id: 6,
        name: '2022-23 Inflation',
        value: '5.25%',
        ci: 6,
        points: [
          { x: 773, y: 440, value: '1.5%', label: '2022 - Hiking' },
          { x: 800, y: 340, value: '4.0%', label: '2022 - Hiking' },
          { x: 789, y: 292, value: '5.25%', label: '2023 - Peak' },
          { x: 806, y: 292, value: '5.25%', label: '2023 - Hold' }
        ]
      }
    ];

    var maxPointCount = Math.max.apply(null, series.map(function (entry) {
      return entry.points.length;
    }));

    function buildStepPath(points) {
      var d = '';
      points.forEach(function (point, index) {
        if (index === 0) {
          d += 'M' + point.x + ',' + point.y;
          return;
        }
        d += ' H' + point.x + ' V' + point.y;
      });
      return d;
    }

    series.forEach(function (entry, seriesIndex) {
      var sg = ctx.el('g', {
        id: 'sg-' + entry.id,
        'class': 'sg',
        'data-series-id': String(entry.id),
        'data-series-index': String(seriesIndex)
      });
      var path = ctx.el('path', {
        'class': 'sline series-' + entry.ci + ' use-series-stroke',
        d: buildStepPath(entry.points)
      });

      sg.appendChild(path);
      entry.points.forEach(function (point, pointIndex) {
        var dotGroup = ctx.el('g', {
          'class': 'dot-g',
          'data-series-index': String(seriesIndex),
          'data-point-index': String(pointIndex)
        });
        var dotRing = ctx.el('circle', {
          cx: point.x,
          cy: point.y,
          r: 5,
          'class': 'dot-ring series-' + entry.ci + ' use-series-stroke'
        });
        var dotCore = ctx.el('circle', {
          cx: point.x,
          cy: point.y,
          r: 3,
          'class': 'series-' + entry.ci
        });
        var hit = ctx.el('circle', {
          cx: point.x,
          cy: point.y,
          r: 12,
          'class': 'dot-hit',
          'data-value': point.value,
          'data-label': point.label,
          'data-meta': entry.name,
          'data-series-id': String(entry.id),
          'data-series-index': String(seriesIndex),
          'data-point-index': String(pointIndex),
          'data-item-cx': String(point.x),
          'data-item-top': String(point.y)
        });

        dotGroup.appendChild(dotRing);
        dotGroup.appendChild(dotCore);
        sg.appendChild(dotGroup);
        sg.appendChild(hit);
        hit._dotGroup = dotGroup;
        pointItems.push(hit);
      });

      dataLayerEl.appendChild(sg);
      seriesGroups.push(sg);
    });

    ctx.initStandardLegend({
      legendEl: legendRoot,
      title: 'SERIES',
      labelMaxWidth: 118,
      items: series.map(function (entry) {
        return { label: entry.name, value: entry.value, cls: 'series-' + entry.ci };
      })
    });

    ctx.initRevealSequence(seriesGroups, {
      animationName: 'fadeIn',
      duration: SERIES_REVEAL_DURATION,
      easing: 'ease-out',
      delays: seriesGroups.map(function (_, index) {
        return ctx.getStaggerDelay(index, seriesGroups.length, 1.0);
      })
    });

    var seriesHover = ctx.initSeriesHoverController({
      hoverLayer: dataLayerEl,
      seriesIds: series.map(function (entry) { return entry.id; }),
      pointCount: maxPointCount,
      lineSelector: '#sg-{id}'
    });

    ctx.initStandardTooltip(dataLayerEl, pointItems, {
      tip: document.getElementById('tip'),
      plotL: 68,
      plotR: 832,
      plotT: 100,
      plotB: 500,
      placement: 'side',
      minWidth: 220,
      paddingX: 20,
      paddingY: 18,
      lineHeights: [42, 32, 32],
      trackPointer: false,
      getAnchor: function (itemEl) {
        return {
          x: Number(itemEl.getAttribute('data-item-cx')) || 0,
          y: Number(itemEl.getAttribute('data-item-top')) || 0
        };
      },
      getContent: function (itemEl) {
        return {
          primary: itemEl.getAttribute('data-value') || '',
          label: itemEl.getAttribute('data-label') || '',
          meta: itemEl.getAttribute('data-meta') || ''
        };
      },
      onActivate: function (itemEl) {
        seriesHover.activate(itemEl);
      },
      onDeactivate: function () {
        seriesHover.clear();
      },
      leaveTarget: dataLayerEl
    });

    ctx.markReadyAfterReveal(dataLayerEl, {
      delays: seriesGroups.map(function (_, index) {
        return ctx.getStaggerDelay(index, seriesGroups.length, 1.0);
      }),
      duration: SERIES_REVEAL_DURATION,
      buffer: 0.1
    });
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
